import { unstable_cache } from 'next/cache';

export type Post = {
  id: string;
  title: string;
  content: string;
};

const posts: Post[] = [];

export async function createPost(formData: FormData) {
  'use server';

  const title = String(formData.get('title') ?? '').trim();
  const content = String(formData.get('content') ?? '').trim();

  if (!title) {
    throw new Error('Title is required');
  }

  const post: Post = {
    id: crypto.randomUUID(),
    title,
    content,
  };

  posts.unshift(post);

  // Invalidate the posts tag and block stale content from being served.
  // updateTag guarantees the cached value is treated as expired immediately.
  // eslint-disable-next-line @typescript-eslint/no-explicit-any
  (await import('next/cache')).updateTag('posts');

  return post;
}

export const getPosts = unstable_cache(
  async () => posts,
  ['posts'],
  { tags: ['posts'] }
);

